({ content, filename }) => {
    if (!filename)
      return;
    const basename = path.basename(filename);
    if (basename.startsWith("+page.") || basename.startsWith("+layout.")) {
      const match = content.match(options_regex);
      if (match && match.index !== void 0 && !should_ignore(content, match.index)) {
        const fixed = basename.replace(".svelte", "(.server).js/ts"), message = `
${colors.bold().red(path.relative(".", filename))}
\`${match[1]}\` will be ignored \u2014 move it to ${fixed} instead. See https://svelte.dev/docs/kit/page-options for more information.`;
        if (!warned.has(message)) {
          console.log(message);
          warned.add(message);
        }
      }
